selector_to_html = {"a[href=\"#inspect-input\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">2. Inspect input<a class=\"headerlink\" href=\"#inspect-input\" title=\"Link to this heading\">#</a></h2><p>Open the raw volume lazily and read its metadata so we know how many z-planes are available before launching the pipeline.</p>", "a[href=\"#inspect-results\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">6. Inspect results<a class=\"headerlink\" href=\"#inspect-results\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#run-the-pipeline\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">5. Run the pipeline<a class=\"headerlink\" href=\"#run-the-pipeline\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">lcp.pipeline()</span></code> writes <code class=\"docutils literal notranslate\"><span class=\"pre\">data_raw.bin</span></code>, runs CaImAn motion correction into <code class=\"docutils literal notranslate\"><span class=\"pre\">data.bin</span></code>, runs CNMF, synthesizes <code class=\"docutils literal notranslate\"><span class=\"pre\">stat.npy</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">iscell.npy</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">F.npy</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">Fneu.npy</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">spks.npy</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">dff.npy</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">roi_stats.npy</span></code>, and renders the lsp figure set. <code class=\"docutils literal notranslate\"><span class=\"pre\">force_reg=True</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">force_detect=True</span></code> ignore any cached outputs.</p>", "a[href=\"#paths\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">1. Paths<a class=\"headerlink\" href=\"#paths\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#pick-every-other-z-plane\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">3. Pick every-other z-plane<a class=\"headerlink\" href=\"#pick-every-other-z-plane\" title=\"Link to this heading\">#</a></h2><p>1-based indexing matches <code class=\"docutils literal notranslate\"><span class=\"pre\">lbm_caiman_python</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">lbm_suite2p_python</span></code>: <code class=\"docutils literal notranslate\"><span class=\"pre\">[1,</span> <span class=\"pre\">3,</span> <span class=\"pre\">5,</span> <span class=\"pre\">...]</span></code> picks every odd plane. Flip to <code class=\"docutils literal notranslate\"><span class=\"pre\">[2,</span> <span class=\"pre\">4,</span> <span class=\"pre\">6,</span> <span class=\"pre\">...]</span></code> for the even subset.</p>", "a[href=\"#lbm-caiman-full-pipeline\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">LBM-CaImAn full pipeline<a class=\"headerlink\" href=\"#lbm-caiman-full-pipeline\" title=\"Link to this heading\">#</a></h1><p>Runs the CaImAn pipeline on every-other z-plane of <code class=\"docutils literal notranslate\"><span class=\"pre\">D:/demo/raw</span></code> and writes suite2p-compatible outputs to <code class=\"docutils literal notranslate\"><span class=\"pre\">D:/demo/caiman-python/</span></code>.</p><p>Output layout per plane (mirrors <code class=\"docutils literal notranslate\"><span class=\"pre\">lbm_suite2p_python.pipeline()</span></code>):\n<code class=\"docutils literal notranslate\"><span class=\"pre\">data_raw.bin</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">data.bin</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">ops.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">stat.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">iscell.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">F.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">Fneu.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">spks.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">dff.npy</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">roi_stats.npy</span></code>, plus diagnostic figures (<code class=\"docutils literal notranslate\"><span class=\"pre\">01_\u202615_*.png</span></code>).</p>", "a[href=\"#caiman-parameters\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">4. CaImAn parameters<a class=\"headerlink\" href=\"#caiman-parameters\" title=\"Link to this heading\">#</a></h2><p>Start from <code class=\"docutils literal notranslate\"><span class=\"pre\">lcp.default_ops()</span></code> and tune for the LBM acquisition. Pixel size sets <code class=\"docutils literal notranslate\"><span class=\"pre\">gSig</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">gSiz</span></code>; patch grid is sized for ~10% cell density per patch.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
